// ===== HALAMAN OCR KK & KTP (standalone, khusus admin, harus online) =====
// Catatan: hasil OCR bersifat bantu-baca, TIDAK dijamin 100% akurat.
// Semua field ditampilkan sebagai input yang bisa dikoreksi manual.
//
// Halaman ini TIDAK memuat app.min.js (mesin kalkulator utama) dan TIDAK
// memakai/menyentuh database responden Asisten PPL (se2026_respondenDB)
// sama sekali. Halaman ini punya database sendiri yang berdiri sendiri
// ("se2026_ocrRespondenDB", tersimpan lokal di perangkat ini).
//
// STRUKTUR HALAMAN (v2):
//   - Tampilan Daftar Responden (default) -> tombol + membuka form kosong.
//   - Form Pendataan (6 tab yang saling eksklusif): KK, KTP, Pendidikan,
//     Meteran PLN, Foto Rumah, Geolokasi.
//   - Simpan -> data masuk ke daftar, form ditutup, balik ke daftar.

const OCR_DB_KEY = "se2026_ocrRespondenDB";
let _dokumenState = { kk: null, ktpList: [], noMeteranListrik: "", fotoRumah: { depan: null, ruangTamu: null }, geolokasi: null };
let _respondenIdAktif = null;
let _namaRespondenAktif = "";
let _activeTab = "kk";

function _getKodeDeviceDokumen(){
  const kode = localStorage.getItem("se2026_kode_aktif_v1") || "";
  const device = localStorage.getItem("se2026_device_uuid_v1") || "";
  return { kode, device };
}

// ---- Data layer MANDIRI (database sendiri, terpisah dari Asisten PPL) ----
function _muatOcrDB(){
  try { return JSON.parse(localStorage.getItem(OCR_DB_KEY) || "{}"); } catch(e){ return {}; }
}
function _simpanOcrDB(db){
  localStorage.setItem(OCR_DB_KEY, JSON.stringify(db));
}

// ---- Status badge per responden (untuk kartu di daftar) ----
function _statusBadges(r){
  const pendidikanOk = !!(r.dokumenKK && r.dokumenKK.anggota && r.dokumenKK.anggota.some(a => a.pendidikanAktual));
  return [
    { label: "KK", ok: !!r.dokumenKK },
    { label: "KTP", ok: !!(r.dokumenKTP && r.dokumenKTP.length) },
    { label: "Pendidikan", ok: pendidikanOk },
    { label: "Meteran", ok: !!r.noMeteranListrik },
    { label: "Foto Rumah", ok: !!(r.fotoRumah && (r.fotoRumah.depan || r.fotoRumah.ruangTamu)) },
    { label: "Geo", ok: !!r.geolokasi }
  ];
}

// ---- View: Daftar Responden ----
function _renderDaftarRespondenList(){
  const el = document.getElementById("daftarRespondenList");
  const emptyEl = document.getElementById("emptyStateResponden");
  const emptySearchEl = document.getElementById("emptyStateSearchResponden");
  const searchBarEl = document.getElementById("searchBarResponden");
  if(!el) return;
  const db = _muatOcrDB();
  const semuaKeys = Object.keys(db).sort((a,b) => (db[b].dibuatPada||"").localeCompare(db[a].dibuatPada||""));
  if(!semuaKeys.length){
    el.innerHTML = "";
    if(emptyEl) emptyEl.style.display = "block";
    if(emptySearchEl) emptySearchEl.style.display = "none";
    if(searchBarEl) searchBarEl.style.display = "none";
    return;
  }
  if(emptyEl) emptyEl.style.display = "none";
  if(searchBarEl) searchBarEl.style.display = "block";
  const q = ((document.getElementById("searchResponden")||{}).value || "").toLowerCase().trim();
  const keys = q ? semuaKeys.filter(k => (db[k].nama || "").toLowerCase().includes(q)) : semuaKeys;
  if(!keys.length){
    el.innerHTML = "";
    if(emptySearchEl) emptySearchEl.style.display = "block";
    return;
  }
  if(emptySearchEl) emptySearchEl.style.display = "none";
  el.innerHTML = keys.map(k => {
    const r = db[k];
    const badges = _statusBadges(r).map(b => `<span class="status-badge ${b.ok?"ok":"no"}">${b.ok?"✓":"○"} ${b.label}</span>`).join("");
    return `<div class="responden-card" data-testid="responden-card-${k}">
      <div class="rc-main" onclick="bukaFormEdit('${k}')" data-testid="responden-card-open-${k}">
        <div class="rc-nama">${r.nama || "(tanpa nama)"}</div>
        <div class="rc-badges">${badges}</div>
      </div>
      <button class="rc-del" onclick="hapusRespondenDariList('${k}')" data-testid="btn-hapus-${k}">🗑️</button>
    </div>`;
  }).join("");
}

function tampilkanDaftarResponden(){
  document.getElementById("viewFormResponden").style.display = "none";
  document.getElementById("viewDaftarResponden").style.display = "block";
  const fab = document.getElementById("btnTambahResponden");
  if(fab) fab.style.display = "flex";
  _renderDaftarRespondenList();
}
function kembaliKeDaftar(){ tampilkanDaftarResponden(); }

// ---- View: Form Pendataan ----
function _kosongkanForm(){
  _dokumenState = { kk: null, ktpList: [], noMeteranListrik: "", fotoRumah: { depan: null, ruangTamu: null }, geolokasi: null };
  const inputNama = document.getElementById("inputNamaRespondenForm");
  if(inputNama) inputNama.value = "";
  _fileFotoKKBase64 = null;
}
function _tampilkanFormView(){
  document.getElementById("viewDaftarResponden").style.display = "none";
  document.getElementById("viewFormResponden").style.display = "block";
  const fab = document.getElementById("btnTambahResponden");
  if(fab) fab.style.display = "none";
  _renderSemuaTab();
  pindahTab("kk");
}
function bukaFormBaru(){
  _respondenIdAktif = null;
  _namaRespondenAktif = "";
  _kosongkanForm();
  const btnHapus = document.getElementById("btnHapusRespondenForm");
  if(btnHapus) btnHapus.style.display = "none";
  _tampilkanFormView();
}
function bukaFormEdit(id){
  const db = _muatOcrDB();
  const r = db[id];
  if(!r) return;
  _respondenIdAktif = id;
  _namaRespondenAktif = r.nama || "";
  _dokumenState = {
    kk: r.dokumenKK || null,
    ktpList: r.dokumenKTP || [],
    noMeteranListrik: r.noMeteranListrik || "",
    fotoRumah: r.fotoRumah || { depan: null, ruangTamu: null },
    geolokasi: r.geolokasi || null
  };
  _fileFotoKKBase64 = null;
  const inputNama = document.getElementById("inputNamaRespondenForm");
  if(inputNama) inputNama.value = _namaRespondenAktif;
  const btnHapus = document.getElementById("btnHapusRespondenForm");
  if(btnHapus) btnHapus.style.display = "block";
  _tampilkanFormView();
  _tarikMetaRespondenUntuk(id);
}
function _ubahNamaRespondenAktif(val){ _namaRespondenAktif = (val || "").trim(); }
function _hapusRespondenDariForm(){
  if(!_respondenIdAktif) return;
  hapusRespondenDariList(_respondenIdAktif);
}

// ---- Tab switching (auto-tersembunyi, hanya tab aktif yang tampil) ----
function pindahTab(tab){
  _activeTab = tab;
  document.querySelectorAll("#tabNavResponden .inner-tab-btn").forEach(btn => {
    btn.classList.toggle("active", btn.getAttribute("data-tab") === tab);
  });
  document.querySelectorAll(".inner-usaha-content").forEach(div => {
    div.classList.toggle("active", div.id === "tab-" + tab);
  });
}

function _renderSemuaTab(){
  const hasilKKEl = document.getElementById("hasilKK");
  const previewKK = document.getElementById("previewFotoKK");
  const statusKK = document.getElementById("statusScanKK");
  const btnScanKK = document.getElementById("btnScanKK");
  if(_dokumenState.kk){
    if(hasilKKEl) hasilKKEl.style.display = "block";
    _isiFormKK();
  } else {
    if(hasilKKEl) hasilKKEl.style.display = "none";
    if(previewKK) previewKK.innerHTML = "";
    if(statusKK) statusKK.textContent = "";
    if(btnScanKK) btnScanKK.disabled = true;
  }
  _renderKtpSlotList();
  _renderPendidikanTable();
  const meteranEl = document.getElementById("noMeteranListrik");
  if(meteranEl) meteranEl.value = _dokumenState.noMeteranListrik || "";
  _renderFotoRumahPreview("depan");
  _renderFotoRumahPreview("ruangTamu");
  _renderGeoHasil();
}

// ---- Sinkron multi-perangkat lewat folder Drive (jalur sendiri, khusus data KK/KTP) ----
function _cariIdBerdasarkanNama(db, nama){
  const namaBersih = (nama||"").trim().toLowerCase();
  return Object.keys(db).find(k => (db[k].nama||"").trim().toLowerCase() === namaBersih) || null;
}

async function _tarikDaftarRespondenDariDrive(){
  const { kode, device } = _getKodeDeviceDokumen();
  if(!kode || !device || !navigator.onLine) return;
  if(typeof window.APPS_SCRIPT_URL !== "string" || !window.APPS_SCRIPT_URL) return;
  try{
    const body = JSON.stringify({ action:"daftarresponden", kode, device });
    const res = await fetch(window.APPS_SCRIPT_URL, { method:"POST", headers:{"Content-Type":"text/plain;charset=utf-8"}, body });
    const hasil = await res.json();
    if(!hasil || !hasil.success || !Array.isArray(hasil.daftar)) return;

    const db = _muatOcrDB();
    let adaBaru = false;
    hasil.daftar.forEach(item => {
      if(!item.nama) return;
      if(_cariIdBerdasarkanNama(db, item.nama)) return; // sudah ada lokal
      const id = "ocr_" + Date.now() + "_" + Math.random().toString(36).slice(2,6);
      db[id] = { id, nama:item.nama, dibuatPada:(new Date()).toISOString(), dokumenKK:null, dokumenKTP:[], noMeteranListrik:"", fotoRumah:{depan:null,ruangTamu:null}, geolokasi:null };
      adaBaru = true;
    });
    if(adaBaru){
      _simpanOcrDB(db);
      _renderDaftarRespondenList();
      showToast("🔄 Daftar responden diperbarui dari perangkat lain");
    }
  }catch(e){ /* gagal tarik daftar -> biarkan, tetap pakai data lokal */ }
}

async function _tarikMetaRespondenUntuk(id){
  const { kode, device } = _getKodeDeviceDokumen();
  const db = _muatOcrDB();
  const r = db[id];
  if(!r || !kode || !device || !navigator.onLine) return;
  if(typeof window.APPS_SCRIPT_URL !== "string" || !window.APPS_SCRIPT_URL) return;
  try{
    const url = window.APPS_SCRIPT_URL + "?action=ambilmeta&kode=" + encodeURIComponent(kode) + "&device=" + encodeURIComponent(device) + "&namaResponden=" + encodeURIComponent(r.nama);
    const res = await fetch(url);
    const hasil = await res.json();
    if(!hasil || !hasil.success || !hasil.meta) return;
    const meta = JSON.parse(hasil.meta);
    const dbTerbaru = _muatOcrDB();
    if(!dbTerbaru[id]) return;
    let berubah = false;
    if(!dbTerbaru[id].dokumenKK && meta.dokumenKK){ dbTerbaru[id].dokumenKK = meta.dokumenKK; berubah = true; }
    if((!dbTerbaru[id].dokumenKTP || !dbTerbaru[id].dokumenKTP.length) && meta.dokumenKTP && meta.dokumenKTP.length){ dbTerbaru[id].dokumenKTP = meta.dokumenKTP; berubah = true; }
    if(!dbTerbaru[id].noMeteranListrik && meta.noMeteranListrik){ dbTerbaru[id].noMeteranListrik = meta.noMeteranListrik; berubah = true; }
    if(!dbTerbaru[id].fotoRumah && meta.fotoRumah){ dbTerbaru[id].fotoRumah = meta.fotoRumah; berubah = true; }
    if(!dbTerbaru[id].geolokasi && meta.geolokasi){ dbTerbaru[id].geolokasi = meta.geolokasi; berubah = true; }
    if(berubah){
      _simpanOcrDB(dbTerbaru);
      if(_respondenIdAktif === id){
        _dokumenState = {
          kk: dbTerbaru[id].dokumenKK || null,
          ktpList: dbTerbaru[id].dokumenKTP || [],
          noMeteranListrik: dbTerbaru[id].noMeteranListrik || "",
          fotoRumah: dbTerbaru[id].fotoRumah || { depan:null, ruangTamu:null },
          geolokasi: dbTerbaru[id].geolokasi || null
        };
        _renderSemuaTab();
      }
      showToast("🔄 Data dimuat dari perangkat lain");
    }
  }catch(e){ /* gagal tarik meta -> biarkan, tetap pakai data lokal */ }
}

async function _pushMetaKeServer(nama){
  const { kode, device } = _getKodeDeviceDokumen();
  if(!kode || !device || !navigator.onLine) return;
  if(typeof window.APPS_SCRIPT_URL !== "string" || !window.APPS_SCRIPT_URL) return;
  try{
    const meta = JSON.stringify({ dokumenKK:_dokumenState.kk, dokumenKTP:_dokumenState.ktpList, noMeteranListrik:_dokumenState.noMeteranListrik, fotoRumah:_dokumenState.fotoRumah, geolokasi:_dokumenState.geolokasi });
    const body = JSON.stringify({ action:"simpanmeta", kode, device, namaResponden:nama, meta });
    await fetch(window.APPS_SCRIPT_URL, { method:"POST", headers:{"Content-Type":"text/plain;charset=utf-8"}, body });
  }catch(e){ /* gagal push -> data tetap aman tersimpan lokal */ }
}

// ---- Kompres gambar di browser sebelum dikirim (hemat kuota & waktu) ----
function _kompresGambar(file, maxWidth){
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = (e) => {
      const img = new Image();
      img.onload = () => {
        const scale = Math.min(1, (maxWidth || 1400) / img.width);
        const canvas = document.createElement("canvas");
        canvas.width = Math.round(img.width * scale);
        canvas.height = Math.round(img.height * scale);
        const ctx = canvas.getContext("2d");
        ctx.drawImage(img, 0, 0, canvas.width, canvas.height);
        const dataUrl = canvas.toDataURL("image/jpeg", 0.72);
        resolve(dataUrl.split(",")[1]);
      };
      img.onerror = reject;
      img.src = e.target.result;
    };
    reader.onerror = reject;
    reader.readAsDataURL(file);
  });
}

function _labelSumberOcr(sumber){
  if(sumber === "gemini") return "via Gemini AI (paling akurat)";
  if(sumber === "cloud-vision") return "via Cloud Vision";
  if(sumber === "drive-fallback") return "via Drive, jalur lain gagal";
  if(sumber === "drive-legacy") return "via Drive (kuota terbatas, setup Gemini/Vision API disarankan)";
  return "sumber tidak diketahui";
}

async function _panggilOcrScan(base64, jenis, namaFile){
  const { kode, device } = _getKodeDeviceDokumen();
  if(!kode || !device){ showToast("⚠️ Belum login, tidak bisa scan dokumen"); return null; }
  if(!navigator.onLine){ showToast("⚠️ Butuh koneksi internet untuk scan OCR"); return null; }
  if(!_namaRespondenAktif){ showToast("⚠️ Isi nama responden dulu sebelum scan"); return null; }
  if(typeof window.APPS_SCRIPT_URL !== "string" || !window.APPS_SCRIPT_URL) return null;

  const body = JSON.stringify({ action:"ocrscan", kode, device, jenis, mimeType:"image/jpeg", namaFile, imageBase64: base64, namaResponden: _namaRespondenAktif });
  const res = await fetch(window.APPS_SCRIPT_URL, { method:"POST", headers:{"Content-Type":"text/plain;charset=utf-8"}, body });
  return await res.json();
}

// ---- Tab 1: KK ----
let _fileFotoKKBase64 = null;
function pilihFotoKK(ev){
  const file = ev.target.files && ev.target.files[0];
  if(!file) return;
  if(!_namaRespondenAktif){ showToast("⚠️ Isi nama responden dulu"); ev.target.value = ""; return; }
  const prev = document.getElementById("previewFotoKK");
  const url = URL.createObjectURL(file);
  if(prev) prev.innerHTML = `<img src="${url}" style="max-width:100%;border-radius:8px;border:1px solid var(--copper)">`;
  const btn = document.getElementById("btnScanKK");
  if(btn){ btn.disabled = true; btn.textContent = "⏳ Menyiapkan gambar..."; }
  _kompresGambar(file, 1600).then(b64 => {
    _fileFotoKKBase64 = b64;
    if(btn){ btn.disabled = false; btn.textContent = "🔍 Scan & Ekstrak Data KK"; }
  }).catch(() => {
    if(btn){ btn.disabled = false; btn.textContent = "🔍 Scan & Ekstrak Data KK"; }
    showToast("⚠️ Gagal memproses gambar");
  });
}

async function scanKK(){
  if(!_fileFotoKKBase64){ showToast("⚠️ Pilih foto KK dulu"); return; }
  const status = document.getElementById("statusScanKK");
  const btn = document.getElementById("btnScanKK");
  if(status) status.textContent = "⏳ Mengunggah & memindai (bisa 10-30 detik)...";
  if(btn) btn.disabled = true;
  try{
    const hasil = await _panggilOcrScan(_fileFotoKKBase64, "kk", "KK_"+Date.now()+".jpg");
    if(!hasil){ if(status) status.textContent = ""; if(btn) btn.disabled = false; return; }
    if(!hasil.success){
      if(status) status.textContent = "❌ " + (hasil.message || "Gagal scan KK");
      if(btn) btn.disabled = false;
      return;
    }
    const f = hasil.fields || {};
    _dokumenState.kk = {
      nomor: f.nomorKK || "",
      kepalaKeluarga: f.kepalaKeluarga || "",
      alamat: f.alamat || "",
      anggota: (f.anggota || []).map(a => ({
        nik: a.nik || "",
        nama: a.nama || "",
        tanggalLahir: a.tanggalLahir || "",
        namaBarisMentah: a.namaBaris || "",
        pendidikanKK: a.pendidikanTerdeteksi || "",
        pendidikanAktual: ""
      })),
      teksMentah: hasil.text || "",
      fileUrl: hasil.fileUrl || ""
    };
    _isiFormKK();
    if(status) status.textContent = "✅ Scan selesai (" + _labelSumberOcr(hasil.sumberOcr) + "). Cek & koreksi data di bawah sebelum disimpan.";
  }catch(e){
    if(status) status.textContent = "❌ Gagal terhubung ke server saat scan.";
  }
  if(btn) btn.disabled = false;
}

function _isiFormKK(){
  const kk = _dokumenState.kk;
  if(!kk) return;
  document.getElementById("hasilKK").style.display = "block";
  document.getElementById("kkNomor").value = kk.nomor || "";
  document.getElementById("kkKepalaKeluarga").value = kk.kepalaKeluarga || "";
  document.getElementById("kkAlamat").value = kk.alamat || "";
  document.getElementById("kkTeksMentah").textContent = kk.teksMentah || "(kosong)";
  _renderKkAnggotaList();
  _renderPendidikanTable();
  _renderKtpSlotList();
}

function _renderKkAnggotaList(){
  const el = document.getElementById("kkAnggotaList");
  if(!el) return;
  const kk = _dokumenState.kk;
  if(!kk || !kk.anggota.length){ el.innerHTML = '<div class="hint">Tidak ada baris anggota terdeteksi otomatis — cek teks mentah OCR, tambahkan manual kalau perlu.</div>'; return; }
  el.innerHTML = kk.anggota.map((a, i) => `
    <div style="background:var(--bg);border:1px solid var(--border);border-radius:8px;padding:10px;margin-bottom:8px">
      <div class="field" style="margin-bottom:8px"><label style="font-size:10px">NAMA ANGGOTA (otomatis dari OCR kalau terdeteksi -- cek &amp; koreksi kalau perlu)</label><div class="input-wrap"><input type="text" value="${a.nama}" oninput="_updateAnggotaKK(${i},'nama',this.value)" placeholder="Isi manual kalau tidak terdeteksi" data-testid="kk-anggota-nama-${i}"></div></div>
      <div class="field" style="margin-bottom:8px"><label style="font-size:10px">NIK</label><div class="input-wrap"><input type="text" value="${a.nik}" oninput="_updateAnggotaKK(${i},'nik',this.value)" data-testid="kk-anggota-nik-${i}"></div></div>
      <div class="field" style="margin-bottom:0"><label style="font-size:10px">TANGGAL LAHIR</label><div class="input-wrap"><input type="text" value="${a.tanggalLahir||''}" oninput="_updateAnggotaKK(${i},'tanggalLahir',this.value)" placeholder="DD-MM-YYYY" data-testid="kk-anggota-tgllahir-${i}"></div></div>
      <div class="hint" style="font-size:11px;margin-top:6px">Baris OCR asli: <i>${a.namaBarisMentah || "-"}</i></div>
    </div>
  `).join("");
}
function _updateAnggotaKK(i, field, val){
  if(!_dokumenState.kk || !_dokumenState.kk.anggota[i]) return;
  _dokumenState.kk.anggota[i][field] = val;
  if(field === "nama") _renderPendidikanTable();
}

// ---- Tab 2: KTP per anggota ----
function tambahSlotKTP(){
  if(!_dokumenState.kk){ showToast("⚠️ Scan KK dulu sebelum menambah foto KTP"); return; }
  _dokumenState.ktpList.push({ anggotaIdx: 0, base64: null, fields: null, teksMentah: "", fileUrl: "", perbedaan: [] });
  _renderKtpSlotList();
}
function _renderKtpSlotList(){
  const el = document.getElementById("ktpSlotList");
  if(!el) return;
  const kk = _dokumenState.kk;
  el.innerHTML = _dokumenState.ktpList.map((slot, i) => {
    const opsiAnggota = (kk && kk.anggota.length) ? kk.anggota.map((a,ai)=>`<option value="${ai}" ${ai===slot.anggotaIdx?"selected":""}>${a.nama || ("Anggota #"+(ai+1))}</option>`).join("") : '<option value="0">(scan KK dulu)</option>';
    const previewHtml = slot.base64 ? `<img src="data:image/jpeg;base64,${slot.base64}" style="max-width:100%;border-radius:8px;border:1px solid var(--copper)">` : "";
    return `
    <div style="background:var(--bg);border:1px solid var(--border);border-radius:8px;padding:10px;margin-bottom:10px">
      <div class="field" style="margin-bottom:8px"><label style="font-size:10px">UNTUK ANGGOTA</label><select onchange="_setAnggotaSlotKTP(${i},this.value)" style="width:100%;padding:8px;border-radius:8px;border:1px solid var(--copper);background:var(--card);color:var(--text)" data-testid="ktp-slot-anggota-${i}">${opsiAnggota}</select></div>
      <div class="photo-capture-row">
        <label class="photo-capture-btn">📷 Kamera<input type="file" accept="image/*" capture="environment" onchange="_pilihFotoKTP(${i},event)" data-testid="ktp-slot-kamera-${i}"></label>
        <label class="photo-capture-btn">🖼️ Galeri<input type="file" accept="image/*" onchange="_pilihFotoKTP(${i},event)" data-testid="ktp-slot-galeri-${i}"></label>
      </div>
      <div id="previewKTP${i}" style="margin-top:6px">${previewHtml}</div>
      <button class="add-btn" onclick="scanKTP(${i})" style="margin-top:8px" data-testid="ktp-slot-scan-${i}">🔍 Scan &amp; Bandingkan dengan KK</button>
      <div id="hasilKTP${i}" style="margin-top:8px"></div>
      <button onclick="_hapusSlotKTP(${i})" style="margin-top:6px;background:none;border:none;color:var(--red);font-size:12px;cursor:pointer" data-testid="ktp-slot-hapus-${i}">🗑️ Hapus slot ini</button>
    </div>
  `;
  }).join("");
  _dokumenState.ktpList.forEach((slot, i) => { if(slot.fields) _bandingkanKtpDenganKK(i); });
}
function _setAnggotaSlotKTP(i, val){ _dokumenState.ktpList[i].anggotaIdx = parseInt(val,10) || 0; }
function _hapusSlotKTP(i){ _dokumenState.ktpList.splice(i,1); _renderKtpSlotList(); }
function _pilihFotoKTP(i, ev){
  const file = ev.target.files && ev.target.files[0];
  if(!file) return;
  if(!_namaRespondenAktif){ showToast("⚠️ Isi nama responden dulu"); ev.target.value = ""; return; }
  const prev = document.getElementById("previewKTP"+i);
  const url = URL.createObjectURL(file);
  if(prev) prev.innerHTML = `<img src="${url}" style="max-width:100%;border-radius:8px;border:1px solid var(--copper)">`;
  _kompresGambar(file, 1600).then(b64 => { _dokumenState.ktpList[i].base64 = b64; }).catch(()=>{ showToast("⚠️ Gagal memproses gambar KTP"); });
}
async function scanKTP(i){
  const slot = _dokumenState.ktpList[i];
  if(!slot || !slot.base64){ showToast("⚠️ Pilih foto KTP dulu"); return; }
  const hasilEl = document.getElementById("hasilKTP"+i);
  if(hasilEl) hasilEl.innerHTML = '<div class="hint">⏳ Memindai KTP...</div>';
  try{
    const hasil = await _panggilOcrScan(slot.base64, "ktp", "KTP_"+Date.now()+".jpg");
    if(!hasil || !hasil.success){
      if(hasilEl) hasilEl.innerHTML = `<div class="hint" style="color:var(--red)">❌ ${(hasil && hasil.message) || "Gagal scan KTP"}</div>`;
      return;
    }
    slot.fields = hasil.fields || {};
    slot.teksMentah = hasil.text || "";
    slot.fileUrl = hasil.fileUrl || "";
    slot.sumberOcr = hasil.sumberOcr || "";
    _bandingkanKtpDenganKK(i);
  }catch(e){
    if(hasilEl) hasilEl.innerHTML = '<div class="hint" style="color:var(--red)">❌ Gagal terhubung ke server saat scan.</div>';
  }
}
function _bandingkanKtpDenganKK(i){
  const slot = _dokumenState.ktpList[i];
  const kk = _dokumenState.kk;
  const anggotaKK = kk ? kk.anggota[slot.anggotaIdx] : null;
  const f = slot.fields || {};
  const perbedaan = [];

  function bandingkan(labelTampil, nilaiKK, nilaiKTP){
    const a = (nilaiKK||"").toString().trim().toUpperCase();
    const b = (nilaiKTP||"").toString().trim().toUpperCase();
    if(!a || !b) return null;
    return a === b ? { label:labelTampil, sama:true, kk:nilaiKK, ktp:nilaiKTP } : { label:labelTampil, sama:false, kk:nilaiKK, ktp:nilaiKTP };
  }

  const cekNama = bandingkan("Nama", anggotaKK ? anggotaKK.nama : "", f.nama);
  const cekNIK = bandingkan("NIK", anggotaKK ? anggotaKK.nik : "", f.nik);
  const cekTglLahir = bandingkan("Tanggal Lahir", anggotaKK ? anggotaKK.tanggalLahir : "", f.tanggalLahir);
  [cekNama, cekNIK, cekTglLahir].forEach(c => { if(c) perbedaan.push(c); });
  slot.perbedaan = perbedaan;

  const hasilEl = document.getElementById("hasilKTP"+i);
  if(!hasilEl) return;
  const adaBeda = perbedaan.some(p => !p.sama);
  let html = `<div style="font-size:12px;padding:8px;border-radius:8px;background:${adaBeda ? "var(--red-bg)" : "var(--green-bg)"};border-left:3px solid ${adaBeda ? "var(--red)" : "var(--green)"}">`;
  html += adaBeda ? "⚠️ <b>Ada perbedaan data KK vs KTP:</b><br>" : "✅ Data KTP cocok dengan KK (untuk field yang bisa dibandingkan).<br>";
  if(perbedaan.length){
    perbedaan.forEach(p => {
      html += `${p.sama?"✅":"⚠️"} <b>${p.label}</b> — KK: "${p.kk}" | KTP: "${p.ktp}"<br>`;
    });
  } else {
    html += '<span class="hint">Belum ada data pembanding di sisi KK untuk field ini (isi manual dulu di tab KK).</span>';
  }
  html += `<div style="margin-top:6px">NIK KTP: <b>${f.nik||"-"}</b> · Nama: <b>${f.nama||"-"}</b> · TTL: <b>${f.tempatTglLahir||"-"}</b> · Alamat: <b>${f.alamat||"-"}</b></div>`;
  html += `<div style="margin-top:4px;opacity:.7;font-size:10.5px">OCR ${_labelSumberOcr(slot.sumberOcr)}</div>`;
  html += `</div>`;
  hasilEl.innerHTML = html;
}

// ---- Tab 3: Pendidikan (KK vs Aktual) ----
const OPSI_PENDIDIKAN = [
  "Tidak/Belum Sekolah",
  "Belum Tamat SD/Sederajat",
  "Tamat SD/Sederajat",
  "SLTP/Sederajat",
  "SLTA/Sederajat",
  "Diploma I/II",
  "Diploma III",
  "Diploma IV/S1",
  "S2",
  "S3"
];
function _renderPendidikanTable(){
  const el = document.getElementById("pendidikanTable");
  if(!el) return;
  const kk = _dokumenState.kk;
  if(!kk || !kk.anggota.length){ el.innerHTML = '<div class="hint">Scan KK dulu supaya daftar anggota otomatis terisi.</div>'; return; }
  el.innerHTML = kk.anggota.map((a, i) => {
    const opsiHtml = '<option value="">-- Pilih pendidikan --</option>' + OPSI_PENDIDIKAN.map(opt => `<option value="${opt}" ${a.pendidikanAktual===opt?"selected":""}>${opt}</option>`).join("");
    return `
    <div style="background:var(--bg);border:1px solid var(--border);border-radius:8px;padding:10px;margin-bottom:8px">
      <div style="font-weight:700;font-size:13px;margin-bottom:6px">${a.nama || ("Anggota #"+(i+1))}</div>
      <div class="field" style="margin-bottom:8px"><label style="font-size:10px">PENDIDIKAN TERCATAT DI KK <span style="opacity:.7">(otomatis dari OCR, terkunci)</span></label><div class="input-wrap" style="opacity:.75"><input type="text" value="${a.pendidikanKK || '(tidak terdeteksi -- cek teks mentah OCR)'}" readonly disabled style="cursor:not-allowed"></div></div>
      <div class="field" style="margin-bottom:6px"><label style="font-size:10px">PENDIDIKAN SEBENARNYA (cek lapangan)</label><div class="input-wrap"><select onchange="_updateAnggotaKK(${i},'pendidikanAktual',this.value)" data-testid="pendidikan-aktual-${i}">${opsiHtml}</select></div></div>
      ${a.pendidikanKK && a.pendidikanAktual ? (a.pendidikanKK.trim().toUpperCase()===a.pendidikanAktual.trim().toUpperCase() ? '<div class="hint" style="color:var(--green)">✅ Sama dengan KK</div>' : '<div class="hint" style="color:var(--red)">⚠️ Berbeda dari catatan KK</div>') : ''}
    </div>
  `;
  }).join("");
}

// ---- Tab 4: Nomor Meter PLN ----
function _updateMeteran(val){ _dokumenState.noMeteranListrik = val; }

// ---- Tab 5: Foto Rumah (langsung diunggah ke Drive, tanpa OCR) ----
function _renderFotoRumahPreview(jenis){
  const data = _dokumenState.fotoRumah[jenis];
  const prevId = jenis === "depan" ? "previewRumahDepan" : "previewRumahRuangTamu";
  const statusId = jenis === "depan" ? "statusRumahDepan" : "statusRumahRuangTamu";
  const prevEl = document.getElementById(prevId);
  const statusEl = document.getElementById(statusId);
  if(prevEl) prevEl.innerHTML = data && data.fileUrl ? `<a href="${data.fileUrl}" target="_blank" rel="noopener" class="hint">🖼️ Lihat foto tersimpan di Drive</a>` : "";
  if(statusEl) statusEl.textContent = data && data.fileUrl ? "✅ Sudah tersimpan ke Google Drive" : "";
}
function pilihFotoRumah(jenis, ev){
  const file = ev.target.files && ev.target.files[0];
  if(!file) return;
  if(!_namaRespondenAktif){ showToast("⚠️ Isi nama responden dulu sebelum ambil foto"); ev.target.value = ""; return; }
  const prevId = jenis === "depan" ? "previewRumahDepan" : "previewRumahRuangTamu";
  const statusId = jenis === "depan" ? "statusRumahDepan" : "statusRumahRuangTamu";
  const prevEl = document.getElementById(prevId);
  const statusEl = document.getElementById(statusId);
  const url = URL.createObjectURL(file);
  if(prevEl) prevEl.innerHTML = `<img src="${url}" style="max-width:100%;border-radius:8px;border:1px solid var(--copper)">`;
  if(statusEl) statusEl.textContent = "⏳ Menyiapkan & mengunggah ke Drive...";
  _kompresGambar(file, 1600).then(async b64 => {
    if(!navigator.onLine){ if(statusEl) statusEl.textContent = "⚠️ Butuh koneksi internet untuk unggah ke Drive"; return; }
    const { kode, device } = _getKodeDeviceDokumen();
    if(typeof window.APPS_SCRIPT_URL !== "string" || !window.APPS_SCRIPT_URL) return;
    try{
      const body = JSON.stringify({ action:"simpanfotoumum", kode, device, namaResponden:_namaRespondenAktif, imageBase64:b64, mimeType:"image/jpeg", namaFile: (jenis==="depan"?"RumahDepan_":"RuangTamu_")+Date.now()+".jpg" });
      const res = await fetch(window.APPS_SCRIPT_URL, { method:"POST", headers:{"Content-Type":"text/plain;charset=utf-8"}, body });
      const hasil = await res.json();
      if(hasil && hasil.success){
        _dokumenState.fotoRumah[jenis] = { fileUrl: hasil.fileUrl };
        _renderFotoRumahPreview(jenis);
      } else {
        if(statusEl) statusEl.textContent = "❌ " + ((hasil && hasil.message) || "Gagal unggah foto ke Drive");
      }
    }catch(e){
      if(statusEl) statusEl.textContent = "❌ Gagal terhubung ke server saat unggah foto";
    }
  }).catch(()=>{ if(statusEl) statusEl.textContent = "⚠️ Gagal memproses gambar"; });
}

// ---- Tab 6: Geolokasi ----
function deteksiGeolokasi(){
  const statusEl = document.getElementById("statusGeolokasi");
  if(!navigator.geolocation){ if(statusEl) statusEl.textContent = "❌ Perangkat/browser ini tidak mendukung geolokasi"; return; }
  if(statusEl) statusEl.textContent = "⏳ Mendeteksi lokasi...";
  navigator.geolocation.getCurrentPosition(pos => {
    _dokumenState.geolokasi = {
      lat: pos.coords.latitude,
      lng: pos.coords.longitude,
      akurasi: Math.round(pos.coords.accuracy || 0),
      waktu: (new Date()).toISOString()
    };
    _renderGeoHasil();
    if(statusEl) statusEl.textContent = "✅ Lokasi terdeteksi";
  }, err => {
    if(statusEl) statusEl.textContent = "❌ Gagal mendeteksi lokasi: " + (err.message || "izin lokasi ditolak/tidak tersedia");
  }, { enableHighAccuracy:true, timeout:15000, maximumAge:0 });
}
function _renderGeoHasil(){
  const geo = _dokumenState.geolokasi;
  const resultEl = document.getElementById("geoResult");
  const textEl = document.getElementById("geoCoordText");
  if(!geo){ if(resultEl) resultEl.style.display = "none"; return; }
  if(textEl) textEl.textContent = `Lat: ${geo.lat.toFixed(6)}, Lng: ${geo.lng.toFixed(6)} (akurasi ±${geo.akurasi}m)`;
  if(resultEl) resultEl.style.display = "block";
}
function _fallbackCopyTeks(text, done){
  try{
    const ta = document.createElement("textarea");
    ta.value = text; ta.style.position = "fixed"; ta.style.opacity = "0";
    document.body.appendChild(ta); ta.select(); document.execCommand("copy");
    document.body.removeChild(ta); done();
  }catch(e){}
}
function salinKoordinat(){
  const geo = _dokumenState.geolokasi;
  if(!geo){ showToast("⚠️ Deteksi lokasi dulu"); return; }
  const teks = `${geo.lat}, ${geo.lng}`;
  const done = () => showToast("📋 Koordinat tersalin");
  if(navigator.clipboard && navigator.clipboard.writeText){
    navigator.clipboard.writeText(teks).then(done).catch(() => _fallbackCopyTeks(teks, done));
  } else {
    _fallbackCopyTeks(teks, done);
  }
}

// ---- Hapus responden (dipanggil dari daftar ATAU dari dalam form) ----
async function hapusRespondenDariList(id){
  const db = _muatOcrDB();
  const nama = (db[id] || {}).nama || "responden ini";
  if(!confirm('Hapus data "' + nama + '" beserta SELURUH foto secara PERMANEN (termasuk dari Google Drive)?\n\nTindakan ini tidak bisa dibatalkan.')) return;

  if(!navigator.onLine){
    showToast("⚠️ Hapus butuh koneksi internet (supaya foto di Drive ikut terhapus, bukan cuma di HP ini)");
    return;
  }

  const { kode, device } = _getKodeDeviceDokumen();
  showToast("⏳ Menghapus dari Drive...");
  try{
    const body = JSON.stringify({ action:"hapusresponden", kode, device, namaResponden: nama });
    const res = await fetch(window.APPS_SCRIPT_URL, { method:"POST", headers:{"Content-Type":"text/plain;charset=utf-8"}, body });
    const hasil = await res.json();
    if(!hasil || !hasil.success){
      showToast("❌ Gagal hapus dari Drive: " + ((hasil && hasil.message) || "tidak diketahui"));
      return;
    }
  }catch(e){
    showToast("❌ Gagal terhubung ke server, penghapusan dibatalkan");
    return;
  }

  delete db[id];
  _simpanOcrDB(db);
  if(_respondenIdAktif === id) _respondenIdAktif = null;
  showToast("🗑️ Responden dihapus permanen (lokal & Drive)");
  tampilkanDaftarResponden();
}

// ---- Simpan & muat data dokumen ke/dari responden aktif ----
function simpanDataResponden(){
  const inputNama = document.getElementById("inputNamaRespondenForm");
  const nama = (inputNama && inputNama.value || "").trim();
  if(!nama){ showToast("⚠️ Nama responden wajib diisi"); return; }
  _namaRespondenAktif = nama;

  const meteran = (document.getElementById("noMeteranListrik")||{}).value || "";
  _dokumenState.noMeteranListrik = meteran;
  if(_dokumenState.kk){
    _dokumenState.kk.nomor = (document.getElementById("kkNomor")||{}).value || "";
    _dokumenState.kk.kepalaKeluarga = (document.getElementById("kkKepalaKeluarga")||{}).value || "";
    _dokumenState.kk.alamat = (document.getElementById("kkAlamat")||{}).value || "";
  }

  const db = _muatOcrDB();
  let id = _respondenIdAktif;
  if(!id){
    id = "ocr_" + Date.now() + "_" + Math.random().toString(36).slice(2,6);
    db[id] = { id, dibuatPada: (new Date()).toISOString() };
  }
  db[id].nama = nama;
  db[id].dokumenKK = _dokumenState.kk;
  db[id].dokumenKTP = _dokumenState.ktpList.map(s => ({ anggotaIdx:s.anggotaIdx, fields:s.fields, teksMentah:s.teksMentah, fileUrl:s.fileUrl, perbedaan:s.perbedaan }));
  db[id].noMeteranListrik = meteran;
  db[id].fotoRumah = _dokumenState.fotoRumah;
  db[id].geolokasi = _dokumenState.geolokasi;
  _respondenIdAktif = id;
  _simpanOcrDB(db);

  showToast("✅ Tersimpan lokal, menyinkron ke Drive...");
  _pushMetaKeServer(nama).then(() => showToast("✅ Tersinkron ke Drive, bisa diakses dari perangkat lain"));
  tampilkanDaftarResponden();
}

